1	/**
2	 * Filesystem scanner per WORKER_LOGIC §4.
3	 *
4	 * - Validates roots at startup (fail-fast)
5	 * - Does NOT follow symlinks
6	 * - Tracks counters for all error conditions
7	 * - Yields file candidates (.psd, .ai) with stat info
8	 *
9	 * Last reviewed: 2026-02-24
10	 */
11	
12	import { readdir, stat, lstat } from "node:fs/promises";
13	import { join, extname, basename, relative } from "node:path";
14	import { config } from "./config.js";
15	import { logger } from "./logger.js";
16	import type { Counters } from "./api-client.js";
17	import { shouldSkipFolder, shouldSkipPath, resetSkipWarnings } from "@popdam/path-filters";
18	
19	const SUPPORTED_EXTENSIONS = new Set([".psd", ".ai", ".pdf"]);
20	
21	// PDF keyword filter: only ingest PDFs whose filename matches these keywords
22	const PDF_KEYWORDS = [
23	  "tech pack", "tech_pack", "techpack", "tech-pack",
24	  "licensing sheet", "licensing-sheet", "licensing_sheet",
25	  "_comp view", "_compview",
26	];
27	
28	export function isPdfCandidate(filename: string): boolean {
29	  const lower = filename.toLowerCase();
30	  return PDF_KEYWORDS.some(kw => lower.includes(kw));
31	}
32	
33	export interface FileCandidate {
34	  absolutePath: string;
35	  relativePath: string; // POSIX canonical (no leading slash)
36	  filename: string;
37	  fileType: "psd" | "ai" | "pdf";
38	  fileSize: number;
39	  modifiedAt: Date;
40	  fileCreatedAt: Date | null;
41	}
42	
43	/**
44	 * Validate that all configured scan roots exist and are readable directories.
45	 * Per WORKER_LOGIC §4.1: refuse to scan if any root is invalid.
46	 */
47	export async function validateScanRoots(counters: Counters, scanRoots?: string[], mountRoot?: string): Promise<boolean> {
48	  const roots = scanRoots ?? config.scanRoots;
49	  const effectiveMountRoot = mountRoot || config.nasContainerMountRoot;
50	  let allValid = true;
51	
52	  for (const root of roots) {
53	    // Validate against NAS_CONTAINER_MOUNT_ROOT
54	    if (!root.startsWith(effectiveMountRoot)) {
55	      logger.error("Scan root is outside NAS_CONTAINER_MOUNT_ROOT", { root, mountRoot: effectiveMountRoot });
56	      counters.roots_invalid++;
57	      allValid = false;
58	      continue;
59	    }
60	
61	    try {
62	      const s = await stat(root);
63	      if (!s.isDirectory()) {
64	        logger.error("Scan root is not a directory", { root });
65	        counters.roots_invalid++;
66	        allValid = false;
67	      }
68	    } catch (e) {
69	      const code = (e as NodeJS.ErrnoException).code;
70	      if (code === "ENOENT") {
71	        logger.error("Scan root does not exist", { root });
72	        counters.roots_invalid++;
73	      } else if (code === "EACCES") {
74	        logger.error("Scan root is not readable", { root });
75	        counters.roots_unreadable++;
76	      } else {
77	        logger.error("Scan root stat failed", { root, error: (e as Error).message });
78	        counters.roots_invalid++;
79	      }
80	      allValid = false;
81	    }
82	  }
83	
84	  return allValid;
85	}
86	
87	/**
88	 * Recursively scan directories and yield file candidates.
89	 * Per WORKER_LOGIC §4.2: do NOT follow symlinks.
90	 */
91	export interface ScanCallbacks {
92	  shouldAbort?: () => boolean;
93	  onDir?: (dirPath: string) => void;
94	  onSkippedDir?: (dirPath: string, reason: string) => void;
95	}
96	
97	export async function* scanFiles(
98	  counters: Counters,
99	  scanRoots?: string[],
100	  callbacks?: ScanCallbacks,
101	  resumeFromDir?: string,
102	  mountRoot?: string,
103	): AsyncGenerator<FileCandidate> {
104	  resetSkipWarnings(); // Reset per-session dedup for skip warnings
105	  const roots = scanRoots ?? config.scanRoots;
106	  const effectiveMountRoot = mountRoot || config.nasContainerMountRoot;
107	  for (const root of roots) {
108	    if (callbacks?.shouldAbort?.()) return;
109	    yield* scanDirectory(root, counters, callbacks, root, resumeFromDir, effectiveMountRoot);
110	  }
111	}
112	
113	async function* scanDirectory(
114	  dirPath: string,
115	  counters: Counters,
116	  callbacks?: ScanCallbacks,
117	  scanRoot?: string,
118	  resumeFromDir?: string,
119	  mountRoot?: string,
120	): AsyncGenerator<FileCandidate> {
121	  if (callbacks?.shouldAbort?.()) return;
122	  let entries;
123	  try {
124	    entries = await readdir(dirPath, { withFileTypes: true });
125	    callbacks?.onDir?.(dirPath);
126	  } catch (e) {
127	    const code = (e as NodeJS.ErrnoException).code;
128	    if (code === "EACCES") {
129	      counters.dirs_skipped_permission++;
130	      logger.warn("Directory not readable, skipping", { dirPath });
131	      callbacks?.onSkippedDir?.(dirPath, "EACCES");
132	    } else {
133	      logger.warn("Failed to read directory", { dirPath, error: (e as Error).message });
134	      callbacks?.onSkippedDir?.(dirPath, code || "unknown");
135	    }
136	    return;
137	  }
138	
139	  // Build a set of lowercased PDF basenames in this directory so we can skip
140	  // .ai files that have a same-named .pdf sibling (PDF is the canonical form).
141	  const pdfBasenames = new Set(
142	    entries
143	      .filter((e) => extname(e.name).toLowerCase() === ".pdf")
144	      .map((e) => e.name.toLowerCase().replace(/\.[^.]+$/, "")),
145	  );
146	
147	  for (const entry of entries) {
148	    if (callbacks?.shouldAbort?.()) return;
149	
150	    const fullPath = join(dirPath, entry.name);
151	
152	    // §4.2: Do NOT follow symlinks
153	    try {
154	      const ls = await lstat(fullPath);
155	      if (ls.isSymbolicLink()) continue;
156	    } catch {
157	      counters.files_stat_failed++;
158	      continue;
159	    }
160	
161	    if (entry.isDirectory()) {
162	      // Skip excluded directories using centralized path-filters
163	      if (shouldSkipFolder(entry.name)) {
164	        logger.debug("Skipping excluded directory", { dirPath: fullPath, folder: entry.name });
165	        counters.dirs_skipped_excluded++;
166	        continue;
167	      }
168	
169	      // Resume support: if resumeFromDir is set and this is a top-level
170	      // subdirectory (one level below scan root), skip dirs that sort before it
171	      if (resumeFromDir && scanRoot && dirPath === scanRoot) {
172	        if (fullPath < resumeFromDir) {
173	          logger.debug("Skipping already-checkpointed directory", { dir: fullPath, resumeFrom: resumeFromDir });
174	          continue;
175	        }
176	      }
177	      yield* scanDirectory(fullPath, counters, callbacks, scanRoot, resumeFromDir, mountRoot);
178	      continue;
179	    }
180	
181	    if (!entry.isFile()) continue;
182	
183	    counters.files_total_encountered++;
184	
185	    const ext = extname(entry.name).toLowerCase();
186	    if (!SUPPORTED_EXTENSIONS.has(ext)) {
187	      const name = entry.name;
188	      const JUNK_FILENAMES = new Set([".DS_Store", ".localized", "Thumbs.db", "desktop.ini"]);
189	      if (
190	        name.startsWith("._") ||
191	        name.startsWith("~") ||
192	        JUNK_FILENAMES.has(name) ||
193	        dirPath.includes("__MACOSX")
194	      ) {
195	        counters.rejected_junk_file++;
196	      } else {
197	        counters.rejected_wrong_type++;
198	      }
199	      continue;
200	    }
201	
202	    // Check full path for excluded segments (catches files nested inside excluded dirs)
203	    if (shouldSkipPath(fullPath, logger.warn)) {
204	      counters.rejected_junk_file++;
205	      continue;
206	    }
207	
208	    // PDF keyword filter: only accept PDFs matching specific document types
209	    if (ext === ".pdf" && !isPdfCandidate(entry.name)) {
210	      counters.rejected_wrong_type++;
211	      continue;
212	    }
213	
214	    // Skip .ai files when a same-named .pdf sibling exists in the same directory.
215	    // The PDF is the canonical distributable; the .ai is the editable source.
216	    if (ext === ".ai") {
217	      const aiBase = entry.name.toLowerCase().replace(/\.[^.]+$/, "");
218	      if (pdfBasenames.has(aiBase)) {
219	        counters.rejected_ai_has_pdf_sibling++;
220	        logger.debug("Skipping .ai with .pdf sibling", { file: fullPath });
221	        continue;
222	      }
223	    }
224	
225	    counters.files_checked++;
226	
227	    try {
228	      const s = await stat(fullPath);
229	
230	      // Build canonical relative path (POSIX, no leading slash) per PATH_UTILS.md §1
231	      const effectiveRoot = mountRoot || config.nasContainerMountRoot;
232	      let relPath = relative(effectiveRoot, fullPath);
233	      relPath = relPath.split("\\").join("/"); // Ensure POSIX
234	      if (relPath.startsWith("/")) relPath = relPath.slice(1);
235	
236	      const fileType: "psd" | "ai" | "pdf" = ext === ".psd" ? "psd" : ext === ".ai" ? "ai" : "pdf";
237	
238	      const candidate: FileCandidate = {
239	        absolutePath: fullPath,
240	        relativePath: relPath,
241	        filename: basename(entry.name),
242	        fileType,
243	        fileSize: s.size,
244	        // modifiedAt = mtime (last content modification, NOT access time)
245	        // fileCreatedAt = birthtime (original creation time, may be null on Linux)
246	        // We intentionally do NOT use atime (last access time) as it changes on read
247	        modifiedAt: s.mtime,
248	        fileCreatedAt: s.birthtime?.getFullYear() > 1970 ? s.birthtime : null,
249	      };
250	
251	      counters.candidates_found++;
252	      yield candidate;
253	    } catch (e) {
254	      counters.files_stat_failed++;
255	      logger.warn("Failed to stat file", { fullPath, error: (e as Error).message });
256	    }
257	  }
258	}
259

1	/**
2	 * PDF Backfill Worker
3	 *
4	 * Processes every PDF asset in the library that hasn't been sampled yet.
5	 * Runs as a self-driven claim loop: claim 25 → process → commit → repeat.
6	 *
7	 * Key differences from runPdfTextSample (sample mode):
8	 *   - Fetches its own work batches via claim-pdf-backfill-batch (no pre-loaded list)
9	 *   - Submits results per-batch instead of accumulating all at the end
10	 *   - Always generates an 800px JPEG thumbnail for assets that are missing one
11	 *   - FILES USED parsing happens server-side in TypeScript (no PL/pgSQL timeout)
12	 *   - Stops cleanly when status becomes "paused" or "completed"
13	 */
14	
15	import { readFile, stat } from "node:fs/promises";
16	import { join } from "node:path";
17	import sharp from "sharp";
18	import { logger } from "./logger.js";
19	import * as api from "./api-client.js";
20	import { uploadThumbnail, uploadPdfPage } from "./uploader.js";
21	import * as mupdf from "mupdf";
22	import { createWorker } from "tesseract.js";
23	import Anthropic from "@anthropic-ai/sdk";
24	import type { AiConfig } from "./pdf-text-sampler.js";
25	import { isAiWithoutPdfCompat } from "./thumbnailer.js";
26	
27	const PDF_SIZE_LIMIT_BYTES = 100 * 1024 * 1024;
28	const THUMBNAIL_WIDTH = 800;
29	
30	// ── AI vision (mirrors pdf-text-sampler.ts) ───────────────────────────────────
31	
32	async function callAiVision(pngBuffer: Buffer, aiConfig: AiConfig): Promise<string> {
33	  const modelId = aiConfig.pdf_extraction?.ai_vision_model_id;
34	  if (!modelId) return "";
35	
36	  const modelDef = aiConfig.models.find((m) => m.id === modelId);
37	  if (!modelDef || !modelDef.capabilities.includes("vision")) return "";
38	
39	  const base64 = pngBuffer.toString("base64");
40	
41	  if (modelDef.provider === "google") {
42	    if (!aiConfig.googleApiKey) return "";
43	    const url = `https://generativelanguage.googleapis.com/v1beta/models/${modelDef.apiModel}:generateContent?key=${aiConfig.googleApiKey}`;
44	    const res = await fetch(url, {
45	      method: "POST",
46	      headers: { "Content-Type": "application/json" },
47	      signal: AbortSignal.timeout(60_000),
48	      body: JSON.stringify({
49	        contents: [{ role: "user", parts: [
50	          { inlineData: { mimeType: "image/png", data: base64 } },
51	          { text: "Extract all text from this document page. Return only the raw extracted text with no commentary." },
52	        ]}],
53	      }),
54	    });
55	    if (!res.ok) throw new Error(`Gemini API ${res.status}`);
56	    // eslint-disable-next-line @typescript-eslint/no-explicit-any
57	    const data = await res.json() as any;
58	    return (data?.candidates?.[0]?.content?.parts?.[0]?.text as string || "").trim();
59	  }
60	
61	  if (modelDef.provider === "anthropic") {
62	    if (!aiConfig.anthropicApiKey) return "";
63	    const anthropic = new Anthropic({ apiKey: aiConfig.anthropicApiKey });
64	    const aiResponse = await anthropic.messages.create({
65	      model: modelDef.apiModel,
66	      max_tokens: 2048,
67	      messages: [{ role: "user", content: [
68	        { type: "image", source: { type: "base64", media_type: "image/png", data: base64 } },
69	        { type: "text", text: "Extract all text from this document page. Return only the raw extracted text with no commentary." },
70	      ]}],
71	    });
72	    const first = aiResponse.content[0];
73	    return (first.type === "text" ? first.text : "").trim();
74	  }
75	
76	  return "";
77	}
78	
79	// ── Process a single PDF ──────────────────────────────────────────────────────
80	
81	async function processOne(
82	  asset: api.BackfillAsset,
83	  fullPath: string,
84	  aiConfig: AiConfig,
85	): Promise<api.BackfillResult> {
86	  const fileStat = await stat(fullPath);
87	  if (fileStat.size > PDF_SIZE_LIMIT_BYTES) {
88	    return {
89	      asset_id: asset.id, filename: asset.filename, relative_path: asset.relative_path,
90	      extraction_method: "skipped", extracted_text: null,
91	      page_count: null, char_count: 0, extraction_error: null,
92	      sample_thumbnail_url: null, asset_thumbnail_url: null,
93	    };
94	  }
95	
96	  if (asset.filename.toLowerCase().endsWith(".ai")) {
97	    const isSentinel = await isAiWithoutPdfCompat(fullPath);
98	    if (isSentinel) {
99	      const sentinelText = "This is an Adobe® Illustrator® File that was saved without PDF Content.";
100	      return {
101	        asset_id: asset.id, filename: asset.filename, relative_path: asset.relative_path,
102	        extraction_method: "pdf_text", extracted_text: sentinelText,
103	        page_count: 1, char_count: sentinelText.length, extraction_error: null,
104	        sample_thumbnail_url: null, asset_thumbnail_url: null,
105	      };
106	    }
107	  }
108	
109	  const buffer = await readFile(fullPath);
110	  let rawText = "";
111	  let numPages: number | null = null;
112	  let mupdfDoc: ReturnType<typeof mupdf.Document.openDocument> | null = null;
113	
114	  // Step 1: mupdf text extraction
115	  try {
116	    mupdfDoc = mupdf.Document.openDocument(buffer, "application/pdf");
117	    numPages = mupdfDoc.countPages();
118	    const parts: string[] = [];
119	    for (let p = 0; p < numPages; p++) {
120	      parts.push(mupdfDoc.loadPage(p).toStructuredText("preserve-whitespace").asText());
121	    }
122	    rawText = parts.join("\n").trim();
123	  } catch (e) {
124	    logger.warn("PDF backfill: mupdf text failed", { filename: asset.filename, error: (e as Error).message });
125	  }
126	
127	  // Step 2: render page 0 — always when thumbnail needed, or when text < 100 chars (OCR fallback)
128	  let pngBuffer: Buffer | null = null;
129	  let sampleThumbnailUrl: string | null = null;
130	  let assetThumbnailUrl: string | null = null;
131	
