32	async function authenticateAgent(
33	  req: Request,
34	): Promise<{ agentId: string; agentName: string; agentType: string } | Response> {
35	  const agentKey = req.headers.get("x-agent-key");
36	  if (!agentKey) return err("Missing x-agent-key header", 401);
37	
38	  const db = serviceClient();
39	  const encoder = new TextEncoder();
40	  const hashBuffer = await crypto.subtle.digest(
41	    "SHA-256",
42	    encoder.encode(agentKey),
43	  );
44	  const hashHex = Array.from(new Uint8Array(hashBuffer))
45	    .map((b) => b.toString(16).padStart(2, "0"))
46	    .join("");
47	
48	  const { data, error } = await db
49	    .from("agent_registrations")
50	    .select("id, agent_name, agent_type")
51	    .eq("agent_key_hash", hashHex)
52	    .maybeSingle();
53	
54	  if (error) return err(`Auth lookup failed: ${error.message}`, 500);
55	  if (!data) return err("Invalid agent key", 401);
56	  return { agentId: data.id, agentName: data.agent_name, agentType: data.agent_type };
57	}
