20	RETURNS int LANGUAGE plpgsql AS $$
21	DECLARE
22	  v_sku     text;
23	  v_text    text;
24	  v_lines   text[];
25	  v_in_sect boolean := false;
26	  v_line    text;
27	  v_trimmed text;
28	  v_count   int := 0;
29	BEGIN
30	  SELECT sku INTO v_sku FROM assets WHERE id = p_asset_id;
31	  IF v_sku IS NULL OR v_sku = '' THEN RETURN 0; END IF;
32	
33	  SELECT extracted_text INTO v_text
34	  FROM pdf_text_samples
35	  WHERE asset_id = p_asset_id AND extracted_text IS NOT NULL
36	  ORDER BY sampled_at DESC LIMIT 1;
37	  IF v_text IS NULL THEN RETURN 0; END IF;
38	
39	  v_lines := string_to_array(v_text, E'\n');
40	  FOREACH v_line IN ARRAY v_lines LOOP
41	    v_trimmed := trim(v_line);
42	
43	    -- Detect "Files Used", "Source Files", "Art Files", "Design Files" section headers
44	    IF v_trimmed ~* '^\s*(files?\s+used|source\s+files?|art\s+files?|design\s+files?)\s*:?\s*$' THEN
45	      v_in_sect := true;
46	      CONTINUE;
47	    END IF;
48	
49	    IF v_in_sect THEN
50	      -- Stop at blank line or a new section header (text ending with colon)
51	      IF v_trimmed = '' OR v_trimmed ~ '^\S[^:]*:\s*$' THEN
52	        v_in_sect := false;
53	        CONTINUE;
54	      END IF;
