1	-- Fix: handle "FILES USED: file1, file2" inline format (all on one line after the colon).
2	-- Original regex required the header to be on its own line ($), so it never matched.
3	CREATE OR REPLACE FUNCTION public.parse_pdf_files_used(p_asset_id uuid)
4	RETURNS integer
5	LANGUAGE plpgsql AS $$
6	DECLARE
7	  v_sku     text;
8	  v_text    text;
9	  v_lines   text[];
10	  v_in_sect boolean := false;
11	  v_line    text;
12	  v_trimmed text;
13	  v_count   int := 0;
14	  v_entry   text;
15	  v_inline  text;
16	BEGIN
17	  SELECT sku INTO v_sku FROM assets WHERE id = p_asset_id;
18	  IF v_sku IS NULL OR v_sku = '' THEN RETURN 0; END IF;
19	
20	  SELECT extracted_text INTO v_text
21	  FROM pdf_text_samples
22	  WHERE asset_id = p_asset_id AND extracted_text IS NOT NULL
23	  ORDER BY sampled_at DESC LIMIT 1;
24	  IF v_text IS NULL THEN RETURN 0; END IF;
25	
26	  v_lines := string_to_array(v_text, E'\n');
27	  FOREACH v_line IN ARRAY v_lines LOOP
28	    v_trimmed := trim(v_line);
29	
30	    -- Detect section header; capture any inline content after the colon
31	    IF v_trimmed ~* '^\s*(files?\s+used|source\s+files?|art\s+files?|design\s+files?)\s*:' THEN
32	      v_in_sect := true;
33	      v_inline := trim(regexp_replace(v_trimmed, '(?i)^\s*(files?\s+used|source\s+files?|art\s+files?|design\s+files?)\s*:\s*', ''));
34	      IF v_inline <> '' THEN
35	        -- Comma-separated entries on the same line
36	        FOREACH v_entry IN ARRAY string_to_array(v_inline, ',') LOOP
37	          v_entry := trim(v_entry);
38	          IF v_entry <> '' AND length(v_entry) >= 2 AND NOT v_entry ~ '^\d+$' THEN
39	            INSERT INTO sku_files_used (sku, file_name)
40	            VALUES (v_sku, v_entry)
41	            ON CONFLICT (sku, file_name) DO NOTHING;
42	            v_count := v_count + 1;
43	          END IF;
44	        END LOOP;
45	        v_in_sect := false;
46	      END IF;
47	      CONTINUE;
48	    END IF;
49	
50	    IF v_in_sect THEN
51	      IF v_trimmed = '' OR v_trimmed ~ '^\S[^:]*:\s*$' THEN
52	        v_in_sect := false;
53	        CONTINUE;
54	      END IF;
55	      IF v_trimmed ~ '^\d+$' OR length(v_trimmed) < 2 THEN CONTINUE; END IF;
56	      INSERT INTO sku_files_used (sku, file_name)
57	      VALUES (v_sku, v_trimmed)
58	      ON CONFLICT (sku, file_name) DO NOTHING;
59	      v_count := v_count + 1;
60	    END IF;
61	  END LOOP;
62	  RETURN v_count;
63	END;
64	$$;
